class Solution:
    def countLatticePoints(self, circles):
        # scan the whole bounding box once and test membership in any circle
        maxc = 0
        for x, y, r in circles:
            maxc = max(maxc, x + r, y + r)
        count = 0
        for px in range(0, maxc + 1):
            for py in range(0, maxc + 1):
                for x, y, r in circles:
                    if (px - x) ** 2 + (py - y) ** 2 <= r * r:
                        count += 1
                        break
        return count

