class Solution:
    def countLatticePoints(self, circles):
        pts = set()
        for x, y, r in circles:
            for px in range(x - r, x + r + 1):
                for py in range(y - r, y + r + 1):
                    if (px - x) ** 2 + (py - y) ** 2 <= r * r:
                        pts.add((px, py))
        return len(pts)

