var countLatticePoints = function(circles) {
    const pts = new Set();
    for (const [x, y, r] of circles) {
        for (let px = x - r; px <= x + r; px++) {
            for (let py = y - r; py <= y + r; py++) {
                if ((px - x) * (px - x) + (py - y) * (py - y) <= r * r) {
                    pts.add(px * 1000 + py);
                }
            }
        }
    }
    return pts.size;
};
